class Solution:
    def reverseOnlyLetters(self, s: str) -> str:
        letters = []
        non_letters = []
        for char in s:
            if char.isalpha():
                letters.append(char)
            else:
                non_letters.append(char)
        letters.reverse()
        return ''.join(non_letters + letters)
